import { GoogleGenAI, Type } from "@google/genai";
import { Itinerary, UserPreferences, DayPlan } from '../types';

// FIX: Initialize the GoogleGenAI client directly with the API key from environment variables, as per the guidelines.
// This resolves the TypeScript error related to `import.meta.env` and aligns with the requirement to exclusively use `process.env.API_KEY`.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });


// --- Schemas for the new two-stage generation ---

const initialItinerarySchema = {
    type: Type.OBJECT,
    properties: {
        destination: { type: Type.STRING },
        duration: { type: Type.INTEGER },
        tripTitle: { type: Type.STRING },
        tripSummary: { type: Type.STRING },
        packingList: { type: Type.ARRAY, items: { type: Type.STRING } },
        travelCost: {
            type: Type.OBJECT,
            properties: {
                mode: { type: Type.STRING, enum: ['flight', 'train', 'other'] },
                estimatedCost: { type: Type.STRING },
                costDisclaimer: { type: Type.STRING },
            },
            required: ['mode', 'estimatedCost', 'costDisclaimer'],
        },
        destinationQuote: {
            type: Type.OBJECT,
            properties: {
                quote: { type: Type.STRING },
                author: { type: Type.STRING },
                translation: { type: Type.STRING },
            },
            required: ['quote', 'author', 'translation'],
        },
        localization: {
            type: Type.OBJECT,
            properties: {
                targetLanguage: { type: Type.STRING },
                translatedStrings: {
                    type: Type.OBJECT,
                    properties: {
                        aboutUs: { type: Type.STRING },
                    },
                    required: ['aboutUs'],
                },
            },
            required: ['targetLanguage', 'translatedStrings'],
        },
    },
    required: [
        'destination', 'duration', 'tripTitle', 'tripSummary', 
        'packingList', 'travelCost', 'destinationQuote', 'localization'
    ],
};

const dailyPlanSchema = {
    type: Type.OBJECT,
    properties: {
        day: { type: Type.INTEGER },
        title: { type: Type.STRING },
        summary: { type: Type.STRING },
        activities: {
            type: Type.ARRAY,
            items: {
                type: Type.OBJECT,
                properties: {
                    name: { type: Type.STRING },
                    description: { type: Type.STRING },
                    location: { type: Type.STRING },
                    latitude: { type: Type.NUMBER },
                    longitude: { type: Type.NUMBER },
                    time: { type: Type.STRING },
                    activityType: { type: Type.STRING },
                },
                required: ['name', 'description', 'location', 'latitude', 'longitude', 'time', 'activityType'],
            },
        },
    },
    required: ['day', 'title', 'summary', 'activities'],
};

const allDailyPlansSchema = {
    type: Type.OBJECT,
    properties: {
        dailyPlans: {
            type: Type.ARRAY,
            items: dailyPlanSchema
        }
    },
    required: ['dailyPlans']
};


async function callAI<T>(prompt: string, schema: object): Promise<T> {
    try {
        // FIX: Updated model to gemini-3-flash-preview for text-based itinerary generation as per latest coding guidelines.
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
            },
        });
        const jsonText = response.text.trim();
        return JSON.parse(jsonText) as T;
    } catch (error) {
        console.error("AI call failed:", error);
        if (error instanceof Error) {
            if (error.message.includes('JSON')) {
                throw new Error("The AI returned an unexpected format. Let's try again.");
            }
             if (error.message.includes('quota')) {
                throw new Error("Failed to call the Gemini API, quota exceeded: you have reached the daily limit of requests for this model. Please select a different model, or try again tomorrow.");
            }
            throw new Error(`Failed to generate content: ${error.message}`);
        }
        throw new Error("An unknown error occurred during AI generation.");
    }
}

export async function* generateItinerary(preferences: UserPreferences): AsyncGenerator<Partial<Itinerary>> {
    const { origin, destination, duration, interests, budget } = preferences;

    // --- STAGE 1: Get the initial "above-the-fold" content (1st API Call) ---
    const initialPrompt = `
        You are an expert travel planner. A user is planning a trip.
        Generate the initial, high-level details for their trip as a JSON object.
        DO NOT generate the detailed daily plans yet.

        **User Preferences:**
        - **Origin:** ${origin}
        - **Destination:** ${destination}
        - **Trip Duration:** ${duration} days
        - **Interests:** ${interests.join(', ')}
        - **Budget:** ${budget}

        **Your Task:**
        Create a JSON object that includes:
        1.  **tripTitle:** A catchy and descriptive title.
        2.  **tripSummary:** A short, 1-2 sentence summary.
        3.  **destination:** The destination name.
        4.  **duration:** The number of days.
        5.  **packingList:** An essential packing list.
        6.  **travelCost:** An estimated travel cost (flight/train).
        7.  **destinationQuote:** A relevant quote about the destination.
        8.  **localization:** The local language and a translation for "About Us".
    `;

    const initialData = await callAI<Omit<Itinerary, 'dailyPlans'>>(initialPrompt, initialItinerarySchema);

    let fullItinerary: Partial<Itinerary> = { ...initialData, dailyPlans: [] };
    yield fullItinerary;

    // --- STAGE 2: Get all daily plans in a single batch (2nd API Call) ---
    const dailyPlansPrompt = `
        You are a travel planner continuing to plan a trip to ${destination} for a user with interests in ${interests.join(', ')}.
        The total trip duration is ${duration} days.

        **Your Task:**
        Generate a detailed itinerary for ALL ${duration} days.
        Provide a JSON object containing a "dailyPlans" array, where each element is a complete plan for a single day.

        **Required JSON Output:**
        An object with a single key "dailyPlans", which is an array of objects. Each object in the array must contain:
        -   **day:** The day number (e.g., 1, 2, ...).
        -   **title:** A thematic title for the day.
        -   **summary:** A brief summary of the day's activities.
        -   **activities:** An array of 3-5 activities. Each activity MUST have a name, description, location, precise latitude/longitude, a suggested time, and an activity type.
    `;

    const dailyPlansData = await callAI<{ dailyPlans: DayPlan[] }>(dailyPlansPrompt, allDailyPlansSchema);

    fullItinerary.dailyPlans = dailyPlansData.dailyPlans;
    yield { ...fullItinerary };

    fullItinerary.isComplete = true;
    yield fullItinerary;
}

