async function callAI<T>(prompt: string, schema: object): Promise<T> {
    // Guidelines recommend creating a new instance before making an API call
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: schema,
            },
        });

        // Clean the response text in case the model includes markdown formatting
        const rawText = response.text || "";
        const jsonText = rawText.replace(/```json|```/g, "").trim();

        if (!jsonText) {
            throw new Error("AI returned an empty response.");
        }

        return JSON.parse(jsonText) as T;
    } catch (error: any) {
        console.error("AI call failed:", error);
        if (error instanceof Error) {
            if (error.message.includes('JSON')) {
                throw new Error("The AI returned an invalid data format. Please try again.");
